library(shiny)
library(bslib)
library(dplyr)
resultados &lt;- read.csv("data/results.csv")
ui &lt;- page_sidebar(
  title = "AnĆ”lisis resultados FIFA",
  sidebar = sidebar(
    title = "SelecciĆ³n",
    selectizeInput(
      "sel_pais",
      "Selecciona un paĆ­s:",
      choices = unique(resultados$home_team)
    )
  ),
  actionButton("btn_mensaje", "Mostrar mensaje"),
  actionLink("lnk_mensaje", "Mostrar mensaje con link")
)

server &lt;- function(input, output, session) {
  observeEvent(input$btn_mensaje, {
    showNotification(
      paste("Has seleccionado:", input$sel_pais),
      type = "message"
    )
  })
  observeEvent(input$lnk_mensaje, {
    showModal(
      modalDialog(
        title = "Mensaje",
        paste("Has seleccionado:", input$sel_pais),
        footer = tagList(
          modalButton("Cerrar"),
          actionButton("btn_mas_info", "MĆ”s info")
        )
      )
    )
  })
}

shinyApp(ui, server)

