Ejemplo carga y descarga de ficheros

library(shiny);library(bslib);library(reactable);library(dplyr);library(ggiraph);library(ggplot2)
ui &lt;- page_navbar(
  title = "AnĆ”lisis resultados FIFA",
  sidebar = sidebar(
    title = "SelecciĆ³n",
    fileInput("archivo", "Subir archivo CSV", accept = ".csv"),
    uiOutput("sel_pais_ui"),
    actionButton("boton", "cargar rivales"),
    uiOutput("sel_rival_ui")
  ),
  nav_panel(
    title = "Partidos",
    downloadButton("descargar", "Descargar datos"),
    reactableOutput("tabla_partidos"),
      verbatimTextOutput("num_partidos")
  ),
  nav_panel(title = "GrĆ”fico",
    girafeOutput("plot"))
)

server &lt;- function(input, output, session) {
    resultados &lt;- eventReactive(input$archivo, {
        read.csv(input$archivo$datapath)
    })
    observeEvent(input$boton, {
    rivales &lt;- resultados() |&gt;
      filter(home_team == input$sel_pais) |&gt;
      pull(away_team) |&gt;
      unique()
    output$sel_rival_ui &lt;- renderUI({
    selectizeInput("sel_rival", "Selecciona un rival:", choices = rivales)
  })
  })
  output$sel_pais_ui &lt;- renderUI({
    req(resultados())
    selectizeInput(
      "sel_pais",
      "Selecciona un paĆ­s:",
      choices = unique(resultados()$home_team)
    )
  })
  output$tabla_partidos &lt;- renderReactable({
    resultados() |&gt;
      filter(home_team == input$sel_pais) |&gt;
      reactable()
  })
  output$plot &lt;- renderGirafe({
    validate(need(input$sel_rival, "Se requiere un rival. Carga los rivales y selecciona uno para mostrar el grĆ”fico."))
    p &lt;- resultados() |&gt;
      filter(home_team == input$sel_pais, away_team == input$sel_rival) |&gt;
      ggplot(aes(x = date, y = home_score)) +
      geom_line() +
      geom_point_interactive(aes(tooltip = paste("Fecha:", date, "&lt;br&gt;Marcador:", home_score, "-", away_score)))
    girafe(ggobj = p)
  })

  output$descargar &lt;- downloadHandler(
  filename = function() {
    paste("datos-", Sys.Date(), ".csv", sep = "")
  },
  content = function(file) {
    write.csv(resultados(), file) # Escribe los datos reactivos en un archivo CSV
  }
)

}

