Ejemplo mĆ³dulo simple

library(shiny)  
library(bslib)
library(reactable)
library(ggplot2)
library(dplyr)
library(lubridate)
resultados &lt;- read.csv("data/results.csv")
seleccion_ui &lt;- function(id) {
  ns &lt;- NS(id) # Crea un espacio de nombres para el mĆ³dulo
  tagList(
    selectizeInput(ns("pais"), "Selecciona un paĆ­s:", choices = unique(resultados$home_team)),
    verbatimTextOutput(ns("salida"))
  )
}
seleccion_server &lt;- function(id) {
  moduleServer(id, function(input, output, session) {
    output$salida &lt;- renderPrint({
      paste("SelecciĆ³n:", input$pais)
    })
    return(list(pais = reactive(input$pais))) # Devuelve el paĆ­s seleccionado como un valor reactivo
  })
}
# App principal
ui &lt;- bslib::page_fluid(
    bslib::navset_card_underline(
        nav_panel("Panel 1", seleccion_ui("mod1"),
        plotOutput("plot1")), # Llama al mĆ³dulo en la UI
        nav_panel("Panel 2", seleccion_ui("mod2"),
        reactableOutput("tabla2"))  # Llama al
    )
)
server &lt;- function(input, output, session) {
  pais1 &lt;- seleccion_server("mod1") # Llama al mĆ³dulo en el server
  pais2 &lt;- seleccion_server("mod2") # Llama al mĆ³dulo otra vez para la segunda instancia
  output$plot1 &lt;- renderPlot({
    # CĆ³digo para generar el grĆ”fico usando pais1$pais()
    resultados |&gt; filter(home_team == pais1$pais()) |&gt; group_by(year(as.Date(date))) |&gt; summarise(home_score = sum(home_score)) |&gt; ggplot(aes(x = year(as.Date(date)), y = home_score)) + geom_line()
  })
  output$tabla2 &lt;- renderReactable({
    # CĆ³digo para generar la tabla usando pais2$pais()
    resultados |&gt; filter(home_team == pais2$pais()) |&gt; reactable()
  })
}
shinyApp(ui, server)

Mapas interactivos con {ggiraph}

Alternativa interactiva a los mapas de {ggplot2} con geom_sf_interactive()
Sin necesidad de usar {leaflet}, pero con menos opciones de personalizaciĆ³n y sin capas dinĆ”micas

Ejemplo simple con {leaflet}

library(shiny); library(leaflet); library(sf); library(dplyr)
countries_data &lt;- giscoR::gisco_get_countries() |&gt; 
  select(NAME_ENGL, geometry)
resultados &lt;- read.csv("data/results.csv") |&gt; 
  group_by(home_team) |&gt; 
  summarise(total_partidos = n()) |&gt;
  inner_join(countries_data, by = c("home_team" = "NAME_ENGL")) |&gt; 
  st_as_sf()
ui &lt;- fluidPage(
  titlePanel("Mapa interactivo con Leaflet"),
  sidebarLayout(
    sidebarPanel(
      selectizeInput("pais", "Selecciona un paĆ­s:", choices = unique(resultados$home_team))
    ),
    mainPanel(
      leafletOutput("mapa")
    )
  )
)
server &lt;- function(input, output, session) {
  output$mapa &lt;- renderLeaflet({
    bins &lt;- c(quantile(resultados$total_partidos, probs = seq(0, 1, 0.25)), Inf)
    pal &lt;- colorBin("YlOrRd", domain = resultados$total_partidos, bins = bins)
    # Cargar datos geoespaciales (ejemplo con sf)
    resultados |&gt; 
    leaflet() |&gt; 
      addTiles() |&gt; 
      addPolygons(fillColor = ~pal(total_partidos), 
        fillOpacity = 0.5, 
        color = "black", 
        weight = 1, 
        popup = ~paste0("Total partidos: ", total_partidos), 
        label = ~home_team) |&gt; 
      addPolygons(data = resultados |&gt; filter(home_team == input$pais), 
        color = "green", weight = 4) |&gt; 
      addLegend(pal = pal, values = resultados$total_partidos, title = "Total partidos")
  })
}
shinyApp(ui = ui, server = server)

